import React, { useState, useEffect, useRef } from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import Sidebar from './Sidebar';
import { useTheme } from '../hooks/useTheme';

export default function Layout() {
  const { theme } = useTheme();
  const location = useLocation();
  const [opacity, setOpacity] = useState(1);
  const [renderPath, setRenderPath] = useState(location.pathname);
  const timerRef = useRef<any>(null);

  useEffect(() => {
    if (location.pathname === renderPath) return;
    // Clear any pending timer
    if (timerRef.current) clearTimeout(timerRef.current);
    // Fade out
    setOpacity(0);
    timerRef.current = setTimeout(() => {
      setRenderPath(location.pathname);
      // Small frame gap so new content renders before fade-in
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setOpacity(1));
      });
    }, 120);
    return () => clearTimeout(timerRef.current);
  }, [location.pathname]);

  return (
    <div data-theme={theme} style={{ display:'flex', minHeight:'100vh', background:'var(--bg)' }}>
      <Sidebar />
      <main style={{
        flex:1, overflowY:'auto', minWidth:0, width:'100%', position:'relative',
        opacity,
        transition: opacity === 0
          ? 'opacity .1s ease'           // fast fade-out
          : 'opacity .25s ease',         // smooth fade-in
        willChange: 'opacity',
      }}>
        <Outlet key={renderPath} />
      </main>
    </div>
  );
}
